			) PRIMARY KEY (id)`,
			configure: func(t *testing.T, root string) Options {
				payloadDir := filepath.Join(root, "payload")
				writeTextFile(t, filepath.Join(payloadDir, "payload.go"), `package payload

type Payload struct {
	Name string `+"`json:\"name\"`"+`
}
`)
				return Options{
					PackageName: "models",
					Config: &Config{
						Tables: []TableConfig{
							{
								Name: "Runs",
								Columns: []ColumnConfig{
									{
										Name:            "metadata",
										JSONType:        "payload.Payload",
										JSONTypeImports: []string{"payload=" + moduleImportPath(t, payloadDir)},
									},
								},
							},
						},
					},
				}
			},
		},
		"success: writable columns compile with default and generated expressions": {
			ddl: `CREATE TABLE Runs (
				id INT64 NOT NULL,
				created_at TIMESTAMP DEFAULT (CURRENT_TIMESTAMP()),
				name STRING(MAX),
				name_lower STRING(MAX) AS (LOWER(name)) STORED,
			) PRIMARY KEY (id)`,
		},
	}

	for name, tt := range tests {
		t.Run(name, func(t *testing.T) {
			root := newCompileFixtureRoot(t)
			opts := Options{PackageName: "models"}
			if tt.configure != nil {
				opts = tt.configure(t, root)
			}
			outDir := generateFromDDL(t, root, tt.ddl, opts)
			runGoTestDir(t, outDir)
		})
