func newError(method, table string, err error) error {
	code := spanner.ErrCode(err)
	return newErrorWithCode(code, method, table, err)
}

func newErrorWithCode(code codes.Code, method, table string, err error) error {
	return &spannerError{
		code:   code,
		method: method,
		table:  table,
		err:    err,
	}
}

type spannerError struct {
	code   codes.Code
	method string
	table  string
	err    error
}

func (e spannerError) Error() string {
	return fmt.Sprintf("spannerError error in %s(%s): %v", e.method, e.table, e.err)
}

func (e spannerError) Unwrap() error {
	return e.err
}

// GRPCStatus implements a conversion to a gRPC status using `status.Convert(error)`.
//
// If the error is originated from the Spanner library, this returns a gRPC status of
// the original error. It may contain details of the status such as RetryInfo.
func (e spannerError) GRPCStatus() *status.Status {
	var ae *apierror.APIError
	if errors.As(e.err, &ae) {
		return status.Convert(ae)
	}

	return status.New(e.code, e.Error())
}

// JSONString maps a STRING column that stores JSON into a typed Go value.
type JSONString[T any] struct {
	Value T
	Valid bool
}

// NewJSONString creates a valid typed JSON string wrapper.
func NewJSONString[T any](value T) JSONString[T] {
	return JSONString[T]{
		Value: value,
		Valid: true,
	}
}

// EncodeSpanner implements spanner.Encoder.
func (v JSONString[T]) EncodeSpanner() (any, error) {
	if !v.Valid {
		return spanner.NullString{}, nil
	}
	payload, err := json.Marshal(v.Value)
	if err != nil {
		return nil, err
	}
	return spanner.NullString{StringVal: string(payload), Valid: true}, nil
}

// DecodeSpanner implements spanner.Decoder.
func (v *JSONString[T]) DecodeSpanner(input any) error {
	return decodeJSONValue(&v.Value, &v.Valid, input)
}

// IsNull reports whether the underlying value is null.
func (v JSONString[T]) IsNull() bool {
	return !v.Valid
}

// MarshalJSON implements json.Marshaler.
func (v JSONString[T]) MarshalJSON() ([]byte, error) {
	if !v.Valid {
		return []byte("null"), nil
	}
	return json.Marshal(v.Value)
}

// UnmarshalJSON implements json.Unmarshaler.
func (v *JSONString[T]) UnmarshalJSON(payload []byte) error {
	return unmarshalJSONValue(&v.Value, &v.Valid, payload)
}

// JSONValue maps a JSON column into a typed Go value.
type JSONValue[T any] struct {
	Value T
	Valid bool
}

// NewJSONValue creates a valid typed JSON wrapper.
func NewJSONValue[T any](value T) JSONValue[T] {
	return JSONValue[T]{
		Value: value,
		Valid: true,
	}
}

// EncodeSpanner implements spanner.Encoder.
func (v JSONValue[T]) EncodeSpanner() (any, error) {
	if !v.Valid {
		return spanner.NullJSON{}, nil
	}
	return spanner.NullJSON{Value: v.Value, Valid: true}, nil
}

// DecodeSpanner implements spanner.Decoder.
func (v *JSONValue[T]) DecodeSpanner(input any) error {
	return decodeJSONValue(&v.Value, &v.Valid, input)
}

// IsNull reports whether the underlying value is null.
func (v JSONValue[T]) IsNull() bool {
	return !v.Valid
}

// MarshalJSON implements json.Marshaler.
func (v JSONValue[T]) MarshalJSON() ([]byte, error) {
	if !v.Valid {
		return []byte("null"), nil
	}
	return json.Marshal(v.Value)
}

// UnmarshalJSON implements json.Unmarshaler.
func (v *JSONValue[T]) UnmarshalJSON(payload []byte) error {
	return unmarshalJSONValue(&v.Value, &v.Valid, payload)
}

func decodeJSONValue[T any](dst *T, valid *bool, input any) error {
	switch value := input.(type) {
	case nil:
		return unmarshalJSONValue(dst, valid, nil)
	case string:
		return unmarshalJSONValue(dst, valid, []byte(value))
	case *string:
		if value == nil {
			return unmarshalJSONValue(dst, valid, nil)
		}
		return unmarshalJSONValue(dst, valid, []byte(*value))
	case []byte:
		return unmarshalJSONValue(dst, valid, value)
	case spanner.NullString:
		if !value.Valid {
			return unmarshalJSONValue(dst, valid, nil)
		}
		return unmarshalJSONValue(dst, valid, []byte(value.StringVal))
	case spanner.NullJSON:
		if !value.Valid {
			return unmarshalJSONValue(dst, valid, nil)
		}
		payload, err := json.Marshal(value.Value)
		if err != nil {
			return err
		}
		return unmarshalJSONValue(dst, valid, payload)
	default:
		payload, err := json.Marshal(value)
		if err != nil {
			return err
		}
		return unmarshalJSONValue(dst, valid, payload)
	}
}

func unmarshalJSONValue[T any](dst *T, valid *bool, payload []byte) error {
	if payload == nil || string(payload) == "null" {
		var zero T
		*dst = zero
		*valid = false
		return nil
	}

	var decoded T
	if err := json.Unmarshal(payload, &decoded); err != nil {
		return err
	}
	*dst = decoded
	*valid = true
	return nil
}

// encodeAny encodes primitive types that spanner library does not support into spanner types before
// passing to spanner functions.
//
// Suppotted primitive types and user defined types that implement [spanner.Encoder] interface are
// handled in encoding phase inside spanner libirary.
func encodeAny(v any) any {
	switch v.(type) {
	case int8, uint8, int16, uint16, int32, uint32, uint64:
		return &primitiveEncoderDecoder{val: v}
	default:
		return v
	}
}

// decodeAny wraps primitive types that spanner library does not support to decode from spanner types
// by yoPrimitiveDecoder before passing to spanner functions.
//
// Supported primitive types and user defined types that implement [spanner.Decoder] interface are
// handled in decoding phase inside spanner libirary.
func decodeAny(ptr any) any {
	switch ptr.(type) {
	case *int8, *uint8, *int16, *uint16, *int32, *uint32, *uint64:
		return &primitiveEncoderDecoder{val: ptr}
	default:
		return ptr
	}
}

type primitiveEncoderDecoder struct {
	val any
}

var (
	_ spanner.Encoder = (*primitiveEncoderDecoder)(nil)
	_ spanner.Decoder = (*primitiveEncoderDecoder)(nil)
)

// EncodeSpanner implements [spanner.Encoder].
func (d primitiveEncoderDecoder) EncodeSpanner() (any, error) {
	switch vv := d.val.(type) {
	case int8:
		return int64(vv), nil
	case uint8:
		return int64(vv), nil
	case int16:
		return int64(vv), nil
	case uint16:
		return int64(vv), nil
	case int32:
		return int64(vv), nil
	case uint32:
		return int64(vv), nil
	case uint64:
		return int64(vv), nil
	default:
		return d.val, nil
	}
}

// DecodeSpanner implements [spanner.Decoder].
func (d *primitiveEncoderDecoder) DecodeSpanner(val any) error {
	strVal, ok := val.(string)
	if !ok {
		return spanner.ToSpannerError(status.Errorf(codes.FailedPrecondition, "failed to decode customField: %[1]T: %[1]v", val))
	}

	intVal, err := strconv.ParseInt(strVal, 10, 64)
	if err != nil {
		return spanner.ToSpannerError(status.Errorf(codes.FailedPrecondition, "%v wasn't correctly encoded: %v", val, err))
	}

	switch vv := d.val.(type) {
	case *int8:
		*vv = int8(intVal)
	case *uint8:
		*vv = uint8(intVal)
	case *int16:
		*vv = int16(intVal)
	case *uint16:
		*vv = uint16(intVal)
	case *int32:
		*vv = int32(intVal)
	case *uint32:
		*vv = uint32(intVal)
	case *uint64:
		*vv = uint64(intVal)
	default:
		return status.Errorf(codes.Internal, "unexpected type for primitiveEncoderDecoder: %T", d.val)
	}

	return nil
}

