func TestGenerator_Generate_TemplatePathOverride_LegacyFullFileTemplates(t *testing.T) {
	root := newCompileFixtureRoot(t)
	outDir := filepath.Join(root, "models")
	templateDir := filepath.Join(root, "templates")

	files := map[string]string{
		"header.go.tmpl": `// header override
package {{ .PackageName }}

import (
	"context"
	"fmt"

	"cloud.google.com/go/spanner"
	"google.golang.org/api/iterator"
)

var _ = context.Background
var _ = fmt.Sprintf
var _ = spanner.Key{}
var _ = iterator.Done
`,
		"spanner_db.go.tmpl": `//go:build !ignoreheader

package {{ .PackageName }}

import ( // ) inline comment must not terminate the import block
	"context"
)

type SpannerDB interface {
	Query(context.Context)
}

var SpannerLog = func(...any) {}

const SpannerDBOverrideMarker = "spanner override"
`,
		"type.go.tmpl": `// type override banner

package {{ .PackageName }}

import "context"

type {{ .Type.Name }} struct{}

func Find{{ .Type.Name }}ByPrimaryKey(ctx context.Context, db SpannerDB) string {
	_, _ = ctx, db
	return "{{ .Type.Table }}"
}
`,
	}

	for name, content := range files {
		writeTextFile(t, filepath.Join(templateDir, name), content)
	}

	if err := NewGenerator(Options{
		OutDir:       outDir,
		PackageName:  "models",
		TemplatePath: templateDir,
	}).Generate(newSimpleSchema("Users")); err != nil {
		t.Fatalf("Generate() error = %v", err)
	}
	if diff := cmp.Diff([]string{"spanner_db.spanner.go", "users.spanner.go"}, listFiles(t, outDir)); diff != "" {
		t.Fatalf("generated files mismatch (-want +got):\n%s", diff)
	}

	tests := map[string]struct {
		path     string
		contains []string
	}{
		"helper": {
			path: filepath.Join(outDir, "spanner_db.spanner.go"),
			contains: []string{
				`//go:build !ignoreheader`,
				`// header override`,
				`SpannerDBOverrideMarker = "spanner override"`,
			},
		},
		"type": {
			path: filepath.Join(outDir, "users.spanner.go"),
			contains: []string{
				`// header override`,
				`// type override banner`,
				`return "Users"`,
			},
		},
	}

	for name, tt := range tests {
		t.Run(name, func(t *testing.T) {
			content := readTextFile(t, tt.path)
			if got, want := strings.Count(content, "package models"), 1; got != want {
				t.Fatalf("%s package clause count = %d, want %d\n%s", tt.path, got, want, content)
			}
			for _, want := range tt.contains {
				if !strings.Contains(content, want) {
					t.Fatalf("%s missing %q", tt.path, want)
				}
			}
		})
	}
	runGoTestDir(t, outDir)
}

func TestGenerator_Generate_TableSelection(t *testing.T) {
	tests := map[string]struct {
		opts      Options
		wantFiles []string
		wantErr   string
	}{
		"success: ignore tables": {
			opts: Options{
				PackageName:  "models",
				IgnoreTables: []string{"Secrets"},
			},
			wantFiles: []string{
				"spanner_db.spanner.go",
				"users.spanner.go",
			},
		},
		"success: include tables": {
			opts: Options{
				PackageName:   "models",
				IncludeTables: []string{"Secrets"},
			},
			wantFiles: []string{
				"secrets.spanner.go",
				"spanner_db.spanner.go",
			},
		},
		"error: unknown included table": {
			opts: Options{
				PackageName:   "models",
				IncludeTables: []string{"Missing"},
			},
			wantErr: `unknown table "Missing"`,
		},
	}

	for name, tt := range tests {
		t.Run(name, func(t *testing.T) {
			outDir := filepath.Join(t.TempDir(), "models")
			tt.opts.OutDir = outDir
			err := NewGenerator(tt.opts).Generate(newSimpleSchema("Users", "Secrets"))
			if tt.wantErr != "" {
				if err == nil {
					t.Fatalf("Generate() error = nil, want %q", tt.wantErr)
				}
				if !strings.Contains(err.Error(), tt.wantErr) {
					t.Fatalf("Generate() error = %v, want substring %q", err, tt.wantErr)
				}
				return
			}
			if err != nil {
				t.Fatalf("Generate() error = %v", err)
			}

			if diff := cmp.Diff(tt.wantFiles, listFiles(t, outDir)); diff != "" {
				t.Fatalf("generated files mismatch (-want +got):\n%s", diff)
			}
		})
	}
}

func TestGenerator_Generate_NamingOptions(t *testing.T) {
	tests := map[string]struct {
		schema          *Schema
		opts            Options
		wantFiles       []string
		wantTypeSnippet string
	}{
		"success: singularize with suffix": {
			schema: newSimpleSchema("FactoryControls"),
			opts: Options{
				PackageName:     "models",
				SingularizeRows: true,
				RowSuffix:       "Row",
			},
			wantFiles: []string{
				"factorycontrolrow.spanner.go",
				"spanner_db.spanner.go",
			},
			wantTypeSnippet: "type FactoryControlRow struct",
		},
		"success: row name override": {
			schema: newSimpleSchema("FleetPools"),
			opts: Options{
				PackageName: "models",
				Config: &Config{
					Tables: []TableConfig{
						{Name: "FleetPools", RowName: "FleetPoolRow"},
					},
				},
			},
			wantFiles: []string{
				"fleetpoolrow.spanner.go",
				"spanner_db.spanner.go",
			},
			wantTypeSnippet: "type FleetPoolRow struct",
		},
	}

	for name, tt := range tests {
		t.Run(name, func(t *testing.T) {
			outDir := filepath.Join(t.TempDir(), "models")
			tt.opts.OutDir = outDir

			if err := NewGenerator(tt.opts).Generate(tt.schema); err != nil {
				t.Fatalf("Generate() error = %v", err)
			}

			if diff := cmp.Diff(tt.wantFiles, listFiles(t, outDir)); diff != "" {
				t.Fatalf("generated files mismatch (-want +got):\n%s", diff)
			}

			typeFiles := filterFiles(tt.wantFiles, func(name string) bool {
				return strings.HasSuffix(name, ".spanner.go") && !strings.HasPrefix(name, "spanner_")
			})
			if len(typeFiles) != 1 {
				t.Fatalf("expected exactly one type file, got %v", typeFiles)
			}
			content := readTextFile(t, filepath.Join(outDir, typeFiles[0]))
			if !strings.Contains(content, tt.wantTypeSnippet) {
				t.Fatalf("%s missing %q", typeFiles[0], tt.wantTypeSnippet)
			}
		})
	}
}

