    59		if diff := cmp.Diff([]string{"spanner_db.yo.go", "users.yo.go"}, listFiles(t, outDir)); diff != "" {
    60			t.Fatalf("generated files mismatch (-want +got):\n%s", diff)
    61		}
    62	
    63		tests := map[string]struct {
    64			path     string
    65			contains []string
    66		}{
    67			"helper": {
    68				path: filepath.Join(outDir, "spanner_db.yo.go"),
    69				contains: []string{
    70					"Code generated by spanner-manager",
