    72					"type SpannerDB interface",
    73					"var SpannerLog",
    74					"type JSONString[T any] struct",
    75				},
    76			},
    77			"type": {
    78				path: filepath.Join(outDir, "users.yo.go"),
    79				contains: []string{
    80					"Code generated by spanner-manager",
    81					"package models",
    82					"type Users struct",
    83					"UserID int64",
    84					`spanner:"name"`,
    85					"func UsersWritableColumns() []string",
